  );

  const markAsRedeemed = useCallback(async (): Promise<boolean> => {
    if (!accountId) {
      return false;
    }

    return markAsRedeemedService(accountId);
  }, [accountId]);

  return {
    hasRedeemed,
    isLoading,
    isError,
    checkHasRedeemed,
    markAsRedeemed,
  };
}

